            .build()
    }

    private fun setupStripeApiKey(apiKey: String): StripeConfiguration {
        return StripeConfiguration.Builder()
            .setPublishableKey(apiKey)
            .setApplicationId("your_stripe_application_id") // Obtained from the stripe dashboard (not shown)
            .build()
